import{_ as a,o as i,c as o,a2 as t}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"ADR-0003: Preview Bootstrap Access","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/adrs/0003-preview-bootstrap-access.md","filePath":"sovereign-os/adrs/0003-preview-bootstrap-access.md"}'),r={name:"sovereign-os/adrs/0003-preview-bootstrap-access.md"};function s(n,e,l,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0003-preview-bootstrap-access" tabindex="-1">ADR-0003: Preview Bootstrap Access <a class="header-anchor" href="#adr-0003-preview-bootstrap-access" aria-label="Permalink to &quot;ADR-0003: Preview Bootstrap Access&quot;">​</a></h1><p><strong>Status:</strong> Accepted for the Phase 01 preview<br><strong>Date:</strong> 2026-07-21<br><strong>Decision owner:</strong> Project creator<br><strong>Related RFC:</strong> <a href="./../rfcs/0010-raspberry-pi-image-deployment.html">RFC-0010</a></p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The first physical POC proved that Sovereign OS boots, joins an Ethernet network, advertises <code>sovereign.local</code>, serves Pi-hole, and answers DNS queries. It also exposed a headless-onboarding dead end: an image flashed without Raspberry Pi Imager customisation has no accepted SSH credential, while the generated Pi-hole password is readable only from the physical console or a privileged shell.</p><p>Requiring a release manifest, a compatible pre-release Imager, and an SSH key before a user can inspect the appliance is too much friction for the preview.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Phase 01 preview images will provide a temporary bootstrap account:</p><ul><li>username: <code>sovereign</code>;</li><li>initial password: <code>sovereign</code>;</li><li>SSH enabled on the local network with password authentication;</li><li>root SSH login disabled; and</li><li>the bootstrap password expired so the user must replace it at the first successful interactive login before receiving a shell.</li></ul><p>The image must clearly label this credential as public and temporary. Users must connect only from a trusted local network, change the password immediately, and should install an SSH public key and disable password authentication after onboarding.</p><p>Ethernet remains the zero-configuration network path. A logged-in user may configure Wi-Fi later with IWD. Raspberry Pi Imager provisioning remains an optional way to install a user-selected account, SSH key, and Wi-Fi settings while flashing.</p><p>This exception applies only to preview builds. A production release requires a device-unique bootstrap secret, secure claim flow, or equivalent mechanism.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>A headless Ethernet installation is recoverable without reflashing.</li><li>Users can retrieve the unique Pi-hole password and diagnose services.</li><li>The normal custom-image flashing path no longer depends on manifest support.</li><li>Wi-Fi and SSH keys can be configured after first boot.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Every unclaimed preview device has a publicly known LAN credential.</li><li>Forced password change protects subsequent access, not the interval before the first login.</li><li>A hostile device on the same network could claim the account first.</li><li>Password authentication adds brute-force exposure on untrusted networks.</li></ul><h2 id="required-controls" tabindex="-1">Required Controls <a class="header-anchor" href="#required-controls" aria-label="Permalink to &quot;Required Controls&quot;">​</a></h2><ul><li>Document the credential beside every preview download and flashing guide.</li><li>Never expose SSH through router port forwarding or a public interface.</li><li>Force password replacement using account-expiry semantics; a banner or recommendation alone is insufficient.</li><li>Generate unique SSH host keys on first boot.</li><li>Keep root login disabled and do not grant passwordless sudo by default.</li><li>Test that the initial password cannot open a second session after it has been changed.</li><li>Provide documented key installation and password-authentication hardening.</li><li>Replace this design before removing the preview label.</li></ul><h2 id="rejected-alternatives" tabindex="-1">Rejected Alternatives <a class="header-anchor" href="#rejected-alternatives" aria-label="Permalink to &quot;Rejected Alternatives&quot;">​</a></h2><h3 id="require-raspberry-pi-imager-provisioning" tabindex="-1">Require Raspberry Pi Imager provisioning <a class="header-anchor" href="#require-raspberry-pi-imager-provisioning" aria-label="Permalink to &quot;Require Raspberry Pi Imager provisioning&quot;">​</a></h3><p>This is safer but failed the simplest downloaded-image workflow and depends on custom manifest compatibility.</p><h3 id="display-credentials-only-on-an-attached-console" tabindex="-1">Display credentials only on an attached console <a class="header-anchor" href="#display-credentials-only-on-an-attached-console" aria-label="Permalink to &quot;Display credentials only on an attached console&quot;">​</a></h3><p>This excludes headless users and was the failure observed in the physical POC.</p><h3 id="publish-the-pi-hole-password-directly" tabindex="-1">Publish the Pi-hole password directly <a class="header-anchor" href="#publish-the-pi-hole-password-directly" aria-label="Permalink to &quot;Publish the Pi-hole password directly&quot;">​</a></h3><p>This would expose an application administrator secret and still would not provide host diagnostics or Wi-Fi configuration.</p>',25)])])}const b=a(r,[["render",s]]);export{u as __pageData,b as default};
